def solve(series_list: list[str], threshold: float) -> list[int]:
    def parse_series(s: str) -> dict[str, Any]:
        parts = s.split()
        timestamps = []
        values = []
        for i in range(0, len(parts), 2):
            timestamps.append(int(parts[i]))
            values.append(float(parts[i + 1]))
        return {"timestamps": timestamps, "values": values}

    def merge_series(series_list: list[dict[str, Any]]) -> dict[str, Any]:
        all_timestamps = []
        all_values = []
        for s in series_list:
            all_timestamps.extend(s["timestamps"])
            all_values.extend(s["values"])
        combined = sorted(zip(all_timestamps, all_values))
        if not combined:
            return {"timestamps": [], "values": []}
        timestamps, values = zip(*combined)
        return {"timestamps": list(timestamps), "values": list(values)}

    def moving_average(series: dict[str, Any], window_size: int) -> list[float]:
        values = series["values"]
        if window_size <= 0:
            raise ValueError("window_size must be positive")
